def _check_dynamic_default(default: cabc.Mapping[t.Any, t.Any]) -> None:
    """Validate the shape of a dynamic default mapping given as an
    option's ``default``. Keys must be the option declarations of other
    parameters (e.g. ``"--protocol"``) and values must be mappings from
    the stringified value of that parameter to the default to use.
    """
    for key, value in default.items():
        if not isinstance(key, str):
            raise TypeError("Dynamic default keys must be strings")

        if not isinstance(value, dict):
            raise TypeError("Dynamic default values must be dictionaries")

